// Map each palette key -> the CSS custom property name(s) consumed by App.css / index.css.
const VAR_MAP = {
  windowBg: ['--pane-bg'],
  panelBg: ['--controls-bg'],
  panelBorder: ['--divider'],
  menuBg: ['--menu-bg'],
  menuFg: ['--menu-fg'],
  menuHover: ['--menu-highlight'],
  menuHoverFg: ['--menu-hover-fg'],
  textViewBg: ['--textview-bg'],
  leftPaneBg: ['--rsvp-bg'],
  lineNumberFg: ['--line-number-fg'],
  lineUnreadFg: ['--line-unread-fg', '--rsvp-fg'],
  lineReadFg: ['--line-read-fg'],
  sessionReadFg: ['--session-read-fg'],
  navSessionReadFg: ['--nav-session-read-fg'],
  currentLineBg: ['--current-line-bg'],
  currentLineFg: ['--current-line-fg'],
  currentParaBg: ['--current-para-bg'],
  statsFg: ['--stats-fg'],
  emptyFg: ['--empty-fg'],
  metaFg: ['--meta-fg'],
  wpmFg: ['--wpm-fg'],
  statusBarBg: ['--status-bg'],
  statusBarBorder: ['--statusbar-border'],
  statusBarFg: ['--status-fg'],
  buttonBg: ['--btn-bg'],
  buttonFg: ['--btn-fg'],
  buttonBorder: ['--btn-border'],
  buttonHoverBg: ['--btn-hover'],
  buttonPressedBg: ['--btn-pressed'],
  toggleActiveBg: ['--toggle-active-bg'],
  toggleActiveFg: ['--toggle-active-fg'],
  inputBg: ['--input-bg'],
  inputFg: ['--input-fg'],
  inputBorder: ['--input-border'],
  trackBg: ['--track-bg'],
  thumbBg: ['--thumb-bg'],
  gridSplitterBg: ['--splitter-bg'],
};

export function getPalette(name) {
  return THEMES[name] || THEMES['Light'];
}

// Apply a theme by writing CSS custom properties onto the given element (default :root).
export function applyTheme(name, serifFamily, sansFamily, el) {
  const p = getPalette(name);
  const root = el || document.documentElement;
  for (const [key, cssVars] of Object.entries(VAR_MAP)) {
    const v = p[key];
    if (v == null) continue;
    for (const cssVar of cssVars) root.style.setProperty(cssVar, v);
  }
  // The user's chosen font (from the picker) wins; a theme's own font is only a fallback when the
  // user hasn't set one. This makes the font picker authoritative across every theme.
  const serif = serifFamily || p.defaultSerifFont || 'Cambria, Georgia, "Times New Roman", serif';
  const sans = sansFamily || p.defaultSansFont || 'Segoe UI, Arial, sans-serif';
  root.style.setProperty('--serif-family', serif);
  root.style.setProperty('--sans-family', sans);
  root.classList.toggle('theme-dark', !!p.isDark);
  root.classList.toggle('theme-light', !p.isDark);
  return p;
}

// ── TOC heading styling ──────────────────────────────────────────────────────
// Each reading theme gets an "elaborate heading" style pack that fits its mood; the line-view
// styles the lines that are TOC headings with it (a distinct look per tier). Packs are defined in
// CSS (App.css, .hsp-<pack> .toc-head-l{0,1,2}); colours come from the theme's own variables, so a
// pack automatically matches whichever theme is active. The per-tab `tocHeadingStyle` setting can
// force a specific pack ('auto' uses the mapping below, 'off' disables heading styling entirely).
export const HEADING_PACKS = ['classic', 'rule', 'terminal', 'deco', 'ornate', 'engraved', 'neon', 'retro'];
export const DEFAULT_HEADING_PACK = 'classic';

const THEME_HEADING_PACK = {
  'Light': 'classic', 'Dark': 'rule', 'Blue': 'rule', 'Warm Paper': 'ornate',
  'Solarized Light': 'rule', 'Solarized Dark': 'terminal', 'Nord': 'rule', 'Monokai': 'terminal',
  'Zenburn': 'terminal', 'Terminal Green': 'terminal', 'Terminal Amber': 'terminal',
  'Midnight': 'neon', 'Forest': 'ornate', 'Oceanic': 'rule', 'Coffee': 'ornate',
  'Sakura': 'ornate', 'Japan': 'engraved', 'Norse': 'engraved', 'Steampunk': 'ornate',
  '70s': 'retro', '80s': 'neon', '90s': 'retro', '2000s': 'rule', 'Art Deco': 'deco',
  'Victorian': 'ornate', 'Medieval': 'ornate', '60s': 'retro', 'Rome': 'engraved',
  'Greece': 'engraved', 'Egypt': 'engraved',
};

// The heading-style pack a theme uses by default.
export function resolveHeadingPack(themeName) {
  return THEME_HEADING_PACK[themeName] || DEFAULT_HEADING_PACK;
}

// ── Extra themes ─────────────────────────────────────────────────────────────
// Rather than hand-write a full ~39-key palette per theme, derive one from a compact spec
// (background, foreground, accent). Colours are mixed toward black/white for surfaces and toward
// the foreground for dimmed text, which yields coherent palettes from four inputs.
function _rgb(h) {
  h = h.replace('#', '');
  if (h.length === 3) h = h.split('').map((c) => c + c).join('');
  return [parseInt(h.slice(0, 2), 16), parseInt(h.slice(2, 4), 16), parseInt(h.slice(4, 6), 16)];
}
function _hex(n) { return Math.max(0, Math.min(255, Math.round(n))).toString(16).padStart(2, '0'); }
export function mix(a, b, t) {
  const A = _rgb(a), B = _rgb(b);
  return '#' + _hex(A[0] + (B[0] - A[0]) * t) + _hex(A[1] + (B[1] - A[1]) * t) + _hex(A[2] + (B[2] - A[2]) * t);
}

function makeTheme({ isDark, bg, fg, accent, accent2 }) {
  const W = '#ffffff', K = '#000000';
  const surf = (t) => isDark ? mix(bg, W, t) : mix(bg, K, t); // a lighter/darker surface shade
  const dim = (t) => mix(bg, fg, t);                          // text between bg and fg
  const green = accent2 || (isDark ? '#66bb6a' : '#2e7d32');
  const border = surf(0.16);
  const panel = surf(0.05);
  return {
    isDark, windowBg: bg, panelBg: panel, panelBorder: border, menuBg: panel, menuFg: fg,
    menuHover: mix(bg, accent, 0.22), menuHoverFg: isDark ? '#ffffff' : fg,
    textViewBg: isDark ? mix(bg, K, 0.1) : bg, leftPaneBg: surf(0.03),
    lineNumberFg: dim(0.32), lineUnreadFg: fg, lineReadFg: dim(0.46),
    sessionReadFg: accent, navSessionReadFg: green,
    currentLineBg: mix(bg, accent, 0.16), currentLineFg: isDark ? mix(fg, W, 0.15) : fg,
    currentParaBg: mix(bg, accent, 0.07), statsFg: dim(0.55), emptyFg: dim(0.42), metaFg: dim(0.5),
    wpmFg: fg, statusBarBg: surf(0.08), statusBarBorder: border, statusBarFg: dim(0.55),
    buttonBg: surf(0.1), buttonFg: fg, buttonBorder: border, buttonHoverBg: mix(bg, accent, 0.2),
    buttonPressedBg: surf(0.14), toggleActiveBg: accent, toggleActiveFg: '#ffffff',
    inputBg: surf(0.08), inputFg: fg, inputBorder: border, trackBg: surf(0.12), thumbBg: dim(0.4),
    gridSplitterBg: border, fontOverride: null,
  };
}

